import {Pane} from "https://esm.sh/tweakpane";

const config = {
  dispersion: 30,
  refraction: -125,
  smoothness: 3.3,
  frost: 7.5,
  fresnel: .3,
  scale: 5,
  rotation: 0,
}


// - - -

const ctrl = new Pane({
  title: 'config',
  expanded: false,
})

const roundTo = (num, precision = 2) => {
	const factor = Math.pow(10, precision);
	return Math.round(num * factor) / factor;
}

const ptrUpdate = (e)  => {
  const pointer = e.touches ? e.touches[0] : e;
  const bb = card.getBoundingClientRect();

  const offsetX = (pointer.clientX - (bb.x + bb.width / 2)) / bb.width;
  const offsetY = (pointer.clientY - (bb.y + bb.height / 2)) / bb.height;

  card.style.setProperty("--x", roundTo(offsetX));
  card.style.setProperty("--y", roundTo(offsetY));
}

window.addEventListener("mousemove", ptrUpdate);
window.addEventListener("touchmove", ptrUpdate);

// - - -

const ctrlUpdate = () => {
  [xR,xG,xB].map((t,i) => {
    t.scale.baseVal = config.refraction + ((i - 1) * config.dispersion)
  })
  xFrost.setAttribute("stdDeviation", config.frost)
  xSm.setAttribute("stdDeviation", config.smoothness)
  xFresnel.setAttribute("slope", config.fresnel)
  const encoded = `
    <svg 
        xmlns='http://www.w3.org/2000/svg'
        color-interpolation-filters='sRGB' 
        viewBox='0 0 500 500' width='500' height='500' 
      ><defs>
        <linearGradient id='rg' >
          <stop offset='0' stop-color='#ff8000'/>
          <stop offset='1' stop-color='#008000'/>
        </linearGradient>
        <pattern 
          id='flutes' 
          patternTransform='scale(${1 / config.scale}) rotate(${config.rotation})' 
          preserveAspectRatio='xMidYMid slice' 
          width='100' height='100' viewBox='0 0 100 100' 
          patternUnits='userSpaceOnUse'>
          <rect width='100' height='100' style='fill: url(#rg);'/>
        </pattern>
      </defs>
      <rect id='pattern' fill='url(#flutes)' width='100%' height='100%'/>
    </svg>
    `
  xPatt.href.baseVal = `data:image/svg+xml,${encodeURIComponent(encoded)}`
}

// - - -

ctrl
  .addBinding(config, 'dispersion', {
    min: 0,
    max: 50,
    step: 0.5,
  })

ctrl
  .addBinding(config, 'refraction', {
    min: -200,
    max: 200,
    step: 1,
  })

ctrl
  .addBinding(config, 'smoothness', {
    min: 0,
    max: 10,
    step: 0.1,
  })

ctrl
  .addBinding(config, 'frost', {
    min: 0,
    max: 20,
    step: 0.1,
  })

ctrl
  .addBinding(config, 'scale', {
    min: 0.01,
    max: 8,
    step: 0.05,
  })

ctrl
  .addBinding(config, 'rotation', {
    min: 0,
    max: 360,
    step: 1,
  })

ctrl
  .addBinding(config, 'fresnel', {
    min: 0,
    max: 1,
    step: 0.01,
  })

ctrl.on('change', ctrlUpdate)
ctrlUpdate()

style.css:
@import url('https://fonts.googleapis.com/css2?family=Manrope');

:root {
  font-size: clamp(1.5rem, 2vw + 1rem, 2.5rem);
  --clr-bg: #fff;
  --clr-text: #000;

  --tilt: 30deg;
}

body {
  height: 100svh;

  display: grid;
  place-items: center;

  font-family: "Manrope", sans-serif;

  background: var(--clr-bg);
  color: var(--clr-text);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

[defs] {
  position: absolute;
  pointer-events: none;
  opacity: 0;
}

main {
  display: grid;
  padding: 1em;
  max-width: 12rem;
  width: 100%;
  position: relative;
  aspect-ratio: 1;
  z-index: 99;

  grid-template-areas: "stack";
  > * {
    grid-area: stack;
  }

}

main > * {
  --rx: calc(var(--y) * var(--tilt) * -1);
  --ry: calc(var(--x) * var(--tilt));

  transition: transform 1200ms cubic-bezier(.03,.98,.52,.99);
  transform: 
    perspective(900px) 
    rotateX(var(--rx)) rotateY(var(--ry)) 
    translateZ(var(--depth));
  will-change: transform;
}

main img {
  width: 100%;
  height: 100%;
  --depth: -2em;
  /* aspect-ratio: 1; */
  overflow: hidden;
  object-fit: contain;
}

main:not(:hover) > * {
  --rx: 0deg;
  --ry: 0deg;
}

aside {
    position: absolute;
    aspect-ratio: 1;
    inset: 0;
    backdrop-filter: url(#flute);
    background: #0001;
    box-shadow: 0 8px 32px 0 #0003;
    border: 2px solid #0001;
    border-radius: 2em;
    overflow: hidden;
    --depth: 1em;
}
